mapper.select:
SELECT t.*,
       (SELECT COUNT(1) FROM tunnel_port tp WHERE tp.tunnel_code = t.tunnel_code) AS port_count
FROM tunnel t
INNER JOIN cluster c ON c.cluster_id = t.cluster_id
WHERE t.namespace = #{namespace}
  AND c.region = #{region}
  AND t.deleted = 0
  AND t.expiration > #{now}

  AND t.cluster_id = #{clusterId}

ORDER BY t.created_at DESC

SELECT COUNT(1)
FROM tunnel t
INNER JOIN cluster c ON c.cluster_id = t.cluster_id
WHERE t.namespace = #{namespace}
  AND c.region = #{region}
  AND t.deleted = 0
  AND t.expiration > #{now}

SELECT t.*
FROM tunnel t
INNER JOIN cluster c ON c.cluster_id = t.cluster_id
WHERE c.region = #{region}
  AND t.expiration <= #{expirationCutoff}
ORDER BY t.expiration ASC
LIMIT #{limit}

mapper.update:
UPDATE tunnel t
INNER JOIN cluster c ON c.cluster_id = t.cluster_id
SET t.bandwidth_used = t.bandwidth_used + #{usageBytes},
    t.updated_at = #{updatedAt}
WHERE t.tunnel_id = #{tunnelId}
  AND c.region = #{region}
  AND t.deleted = 0
  AND t.expiration > #{updatedAt}
